V6[x_]:=V6B[x]+V6F[x];


ODIM5[x_,d_]:=Module[{T1},
	CreateHelpTensors[];
	T1=
		Which[
			x==1,
			1/(2N-2)S1V2D2[3]T^(3/2-1),
			
			x==2,
			-S5[1]T^(5/2-1),
			
			x==3,
			-S3V2[1]T^(5/2-1),
			
			x==4,
			-S1V4[1]T^(5/2-1),
			
			x==5,
			(1/2)Transpose[S3D2[1],{2,3,1}]T^(3/2-1),
			
			x==6,
			(1/2)S1V2D2[1]T^(3/2-1),
			
			x==7,
			S1V2D2[2]T^(3/2-1)-(1/2)S1V2D2[1]T^(3/2-1),
			
			x==8,
			(1/2)S1V2D2[4]T^(3/2-1),
			
			True, "NOT ALLOWED X VALUE"			
			];
	Normal[T1]/.{N->d}// SparseArray // SimplifySparse
];


ODIM6[x_,d_]:=Module[{T1},
	CreateHelpTensors[];
	T1=
		Which[
			x==1,
			I/(N-2)*(V3D3[1]-2I Contract[V2D4[2],gvvv,{{2,5}}]+I/(N-1) Transpose[Contract[V2D4[2],gvvv,{{2,5}}],{3,1,2}])T^(3/2-1),
			
			x==2,
			-(1/2)*S2V2D2[5]T^(4/2-1),
			
			x==3,
			1/2 (Transpose[V4D2[2],{3,4,1,2}]-Transpose[Contract[V2D4[1],gvvv,gvvv,{{1,5},{2,8}}],{4,1,3,2}]-Transpose[Contract[V2D4[1],gvvv,gvvv,{{1,5},{2,8}}],{4,2,3,1}]),
			
			x==4,
			-Transpose[S4D2[1]T^(4/2-1),{1,3,4,2}],
			
			x==5,
			-S2V2D2[1]T^(4/2-1),
			
			x==6,
			-Transpose[S2V2D2[2],{2,1,3,4}]T^(4/2-1),
			
			x==7,
			S2V2D2[3]T^(4/2-1)-S2V2D2[2]T^(4/2-1)-Transpose[S2V2D2[2],{1,2,4,3}]T^(4/2-1),
			
			x==8,
			-Transpose[V4D2[1],{1,3,4,2}]T^(4/2-1),
			
			x==9,
			-S6[1]T^(6/2-1),
			
			x==10,
			-S4V2[1]T^(6/2-1),
			
			x==11,
			-S2V4[1]T^(6/2-1),
			
			x==12,
			-V6[1]T^(6/2-1),
			
			x==13,
			-(1/(N-1))*V2D4[2]T^(2/2-1),
			
			x==14,
			-(I/2)*S2V1D3[1]T^(3/2-1),
			
			x==15,
			-S2D4[1]T^(2/2-1),
			
			x==16,
			-(I/4)Transpose[V3D3[2],{2,3,1}]T^(3/2-1),
			
			x==17,
			-V2D4[1]T^(2/2-1),
			
			x==18,
			-I/2 V3D3[3]T^(3/2-1),
			
			x==19,
			-1/2 (S2V2D2[4])T^(4/2-1),
			
			x==20,
			(1/6)(V4D2[3])T^(4/2-1),		
			
			True, "NOT ALLOWED X VALUE"
			];
	Normal[T1]/.{N->d}// SparseArray // SimplifySparse
];


