	If[MemberQ[n,20],
		
		eqns=Join[eqns,Thread[Flatten[O[[Position[n,20][[1,1]]]]]==Flatten[ODIM6[20,d]]]];		
		];
	
	eqns = DeleteDuplicates[FullSimplify[eqns]];
	Solve[eqns,\[Alpha]]
];
